package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonPrimitive;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonPrimitive_whenIsJsonPrimitiveTrue_returnsThisAsJsonPrimitive() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonPrimitive()).thenReturn(true);

    // Because getAsJsonPrimitive casts this to JsonPrimitive, we need to mock jsonElement as JsonPrimitive too
    JsonPrimitive primitive = mock(JsonPrimitive.class);
    // We use spy to simulate that jsonElement is also a JsonPrimitive instance
    JsonElement spyElement = spy(jsonElement);
    doReturn(true).when(spyElement).isJsonPrimitive();

    // We need to mock the cast: so we cast spyElement to JsonPrimitive by creating a spy of JsonPrimitive and returning it
    // But since JsonPrimitive extends JsonElement, we can just cast spyElement to JsonPrimitive
    // So let's create a spy JsonPrimitive and stub isJsonPrimitive to true
    JsonPrimitive jsonPrimitive = spy(JsonPrimitive.class);
    doReturn(true).when(jsonPrimitive).isJsonPrimitive();

    // Because the method returns (JsonPrimitive) this, we must call it on jsonPrimitive instance
    JsonPrimitive result = jsonPrimitive.getAsJsonPrimitive();

    assertSame(jsonPrimitive, result);
  }

  @Test
  void getAsJsonPrimitive_whenIsJsonPrimitiveFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonPrimitive()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("JsonElementToString");

    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonPrimitive);
    assertEquals("Not a JSON Primitive: JsonElementToString", exception.getMessage());
  }
}
